package com.example.postgresdemo;

import com.example.postgresdemo.model.Image;
import com.example.postgresdemo.properties.FileProperties;
import com.example.postgresdemo.repository.ImageRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.context.event.ApplicationReadyEvent;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.context.event.EventListener;
import org.springframework.data.jpa.repository.config.EnableJpaAuditing;

import static ch.qos.logback.core.encoder.ByteArrayUtil.hexStringToByteArray;

@SpringBootApplication
@EnableJpaAuditing
@EnableConfigurationProperties({
        FileProperties.class
})
public class PostgresDemoApplication {

    @Autowired
    ImageRepository imageRepository;

    public static void main(String[] args) {
        SpringApplication.run(PostgresDemoApplication.class, args);
    }

    @EventListener(ApplicationReadyEvent.class)
    public void saveImages() {
        byte[] charmander = hexStringToByteArray("");
        byte[] skirtle = hexStringToByteArray("");
        byte[] pikachu = hexStringToByteArray("");

        imageRepository.save(new Image("Charmander", charmander));
        imageRepository.save(new Image("Skirtle", skirtle));
        imageRepository.save(new Image("Pikachu", pikachu));
    }

}
